#include <stdio.h>

typedef unsigned int uint;

int main() {
  uint number = 42;
  printf("Number: %u\n", number);
  return 0;
}
// Output:
// Number: 42

#include <stdio.h>

typedef struct {
  char name[20];
  int age;
  float grade;
} Student;

int main() {
  Student student1;
  student1.name[0] = 'A';
  student1.name[1] = 'l';
  student1.name[2] = 'i';
  student1.name[3] = '\0';
  student1.age = 20;
  student1.grade = 85.5;
  printf("Name: %s, Age: %d, Grade: %.1f\n", student1.name, student1.age, student1.grade);
  return 0;
}
// Output:
// Name: Ali, Age: 20, Grade: 85.5

#include <stdio.h>

typedef union {
  int i;
  float f;
  char c;
} Data;

int main() {
  Data data;
  data.i = 10;
  printf("Integer: %d\n", data.i);
  data.f = 3.14;
  printf("Float: %.2f\n", data.f);
  data.c = 'A';
  printf("Char: %c\n", data.c);
  return 0;
}
// Output:
// Integer: 10
// Float: 3.14
// Char: A

#include <stdio.h>

typedef enum {
  Monday,
  Tuesday,
  Wednesday,
  Thursday,
  Friday,
  Saturday,
  Sunday
} Day;

int main() {
  Day today = Wednesday;
  printf("Today is day number: %d\n", today);
  return 0;
}
// Output:
// Today is day number: 2

#include <stdio.h>

typedef int* IntPtr;

int main() {
  int value = 100;
  IntPtr ptr = &value;
  printf("Value: %d\n", *ptr);
  return 0;
}
// Output:
// Value: 100

#include <stdio.h>

typedef int Float; // Səhv: int tipinə Float adı verilir

int main() {
  Float value = 10;
  printf("Value: %f\n", value); // Səhv: int tipi float kimi çap olunur
  return 0;
}
// Output: (Gözlənilməz nəticə, çünki int tipi %f ilə uyğun deyil)

